SELECT * FROM (
  SELECT no, title, review_count AS reviewCount, avg_rating AS avgRating, cover
    FROM br_book
   WHERE review_count >= #{minReviews}
   ORDER BY avg_rating ${order}, review_count DESC
) WHERE ROWNUM <= #{topN}

SELECT * FROM (
  SELECT no, title, review_count AS reviewCount, avg_rating AS avgRating, cover
    FROM br_book
   ORDER BY review_count DESC
) WHERE ROWNUM <= #{topN}
